#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>

int main() {
    cudaError_t err = cudaSuccess;
    int device = 0;
    err = cudaSetDevice(device);
    if (err != cudaSuccess) {
        printf("cudaSetDevice failed: %s\n", cudaGetErrorString(err));
        return 1;
    }

    cudaDeviceProp prop;
    err = cudaGetDeviceProperties(&prop, device);
    if (err != cudaSuccess) {
        printf("cudaGetDeviceProperties failed: %s\n", cudaGetErrorString(err));
        return 1;
    }

    // Output the SM count
    printf("launch__sm_count: %d\n", prop.multiProcessorCount);

    // Also output other properties for verification if needed
    // printf("device_name: %s\n", prop.name);

    return 0;
}

