#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>

int main() {
    cudaError_t err;
    cudaDeviceProp prop;

    // Get device 0 properties
    err = cudaGetDeviceProperties(&prop, 0);
    if (err != cudaSuccess) {
        printf("cudaGetDeviceProperties failed: %s\n", cudaGetErrorString(err));
        return 1;
    }

    // MultiProcessorCount is the SM count
    int sm_count = prop.multiProcessorCount;

    // Prevent compiler optimization - volatile sink
    volatile int sink = sm_count;
    asm volatile("" : "+r"(sink) : : "memory");

    // Output in required format
    printf("launch__sm_count: %d\n", sink);

    // Additional verification: ensure we can also get via cudaDeviceGetAttribute
    int sm_count_attr = 0;
    err = cudaDeviceGetAttribute(&sm_count_attr, cudaDevAttrMultiProcessorCount, 0);
    if (err == cudaSuccess) {
        // Use as additional check but output only one value
        volatile int sink2 = sm_count_attr;
        asm volatile("" : "+r"(sink2) : : "memory");
    }

    return 0;
}

