        printf("cudaGetDeviceCount failed: %s\n", cudaGetErrorString(err));
        return 1;
    }

    if (deviceCount == 0) {
        printf("No CUDA devices found\n");
        return 1;
    }

    // Use device 0
    err = cudaSetDevice(0);
    if (err != cudaSuccess) {
        printf("cudaSetDevice failed: %s\n", cudaGetErrorString(err));
        return 1;
    }

    // Get device properties
    err = cudaGetDeviceProperties(&prop, 0);
    if (err != cudaSuccess) {
        printf("cudaGetDeviceProperties failed: %s\n", cudaGetErrorString(err));
        return 1;
    }

    // Output the SM count (multiProcessorCount)
    printf("launch__sm_count: %d\n", prop.multiProcessorCount);

    return 0;
}

